/**
 * Build-time generator for caOs SDK runtime identity.
 *
 * Sole authority for the SDK version string: package.json#version.
 * This script is the only writer of src/generated/runtime-identity.ts.
 * Do not edit the generated file by hand.
 */
import { readFileSync, writeFileSync, mkdirSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = join(dirname(fileURLToPath(import.meta.url)), '..');
const pkgPath = join(root, 'package.json');
const outDir = join(root, 'src', 'generated');
const outPath = join(outDir, 'runtime-identity.ts');

const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
const version = typeof pkg.version === 'string' ? pkg.version : null;

if (!version || !/^\d+\.\d+\.\d+/.test(version)) {
  console.error(
    `[generate-runtime-identity] invalid package.json version: ${JSON.stringify(pkg.version)}`
  );
  process.exit(1);
}

const body = `/**
 * GENERATED FILE — DO NOT EDIT BY HAND.
 *
 * Source of truth: package.json#version
 * Regenerated by: scripts/generate-runtime-identity.mjs
 * Recreate: npm run generate
 */
export const CAOS_SDK_VERSION = ${JSON.stringify(version)} as const;
`;

mkdirSync(outDir, { recursive: true });
writeFileSync(outPath, body, 'utf8');
console.log(`[generate-runtime-identity] CAOS_SDK_VERSION = ${version} → ${outPath}`);
